1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	
4	export type SubscriptionPlan = "free" | "pro" | "creative_pro" | "brand_workspace" | "business";
5	
6	export interface SubscriptionLimits {
7	  kiraActionsPerDay: number;
8	  invoicesPerMonth: number;
9	  canvasesPerMonth: number;
10	  hasESignature: boolean;
11	  hasPremiumThemes: boolean;
12	  hasClientPortal: boolean;
13	  hasVerifiedBadge: boolean;
14	  hasFullAnalytics: boolean;
15	  hasUnlimitedInvoices: boolean;
16	  hasUnlimitedCanvases: boolean;
17	  hasInvoiceWatermark: boolean;
18	  hasMultiSeat: boolean;
19	  hasRBAC: boolean;
20	  hasClauseLibrary: boolean;
21	  maxWorkspaces: number;
22	  baseSeats: number;
23	}
24	
25	export interface SubscriptionState {
26	  plan: SubscriptionPlan;
27	  status: string;
28	  isLoading: boolean;
29	  isPro: boolean;
30	  isBusiness: boolean;
31	  isBrandWorkspace: boolean;
32	  isFree: boolean;
33	  limits: SubscriptionLimits;
34	  kiraActionsToday: number;
35	  kiraActionsLimit: number;
36	  invoicesUsedThisMonth: number;
37	  canvasesUsedThisMonth: number;
38	}
39	
40	const PRO_LIMITS: SubscriptionLimits = {
41	  kiraActionsPerDay: 40,
42	  invoicesPerMonth: Infinity,
43	  canvasesPerMonth: Infinity,
44	  hasESignature: true,
45	  hasPremiumThemes: true,
46	  hasClientPortal: true,
47	  hasVerifiedBadge: true,
48	  hasFullAnalytics: true,
49	  hasUnlimitedInvoices: true,
50	  hasUnlimitedCanvases: true,
51	  hasInvoiceWatermark: false,
52	  hasMultiSeat: false,
53	  hasRBAC: false,
54	  hasClauseLibrary: false,
55	  maxWorkspaces: Infinity,
56	  baseSeats: 1,
57	};
58	
59	const BUSINESS_LIMITS: SubscriptionLimits = {
60	  kiraActionsPerDay: 200,
61	  invoicesPerMonth: Infinity,
62	  canvasesPerMonth: Infinity,
63	  hasESignature: true,
64	  hasPremiumThemes: true,
65	  hasClientPortal: true,
66	  hasVerifiedBadge: true,
67	  hasFullAnalytics: true,
68	  hasUnlimitedInvoices: true,
69	  hasUnlimitedCanvases: true,
70	  hasInvoiceWatermark: false,
71	  hasMultiSeat: true,
72	  hasRBAC: true,
73	  hasClauseLibrary: true,
74	  maxWorkspaces: Infinity,
75	  baseSeats: 3,
76	};
77	
78	const PLAN_LIMITS: Record<SubscriptionPlan, SubscriptionLimits> = {
79	  free: {
80	    kiraActionsPerDay: 10,
81	    invoicesPerMonth: 3,
82	    canvasesPerMonth: 5,
83	    hasESignature: false,
84	    hasPremiumThemes: false,
85	    hasClientPortal: false,
86	    hasVerifiedBadge: false,
87	    hasFullAnalytics: false,
88	    hasUnlimitedInvoices: false,
89	    hasUnlimitedCanvases: false,
90	    hasInvoiceWatermark: true,
91	    hasMultiSeat: false,
92	    hasRBAC: false,
93	    hasClauseLibrary: false,
94	    maxWorkspaces: 1,
95	    baseSeats: 1,
96	  },
97	  pro:           PRO_LIMITS,
98	  creative_pro:  PRO_LIMITS,
99	  business:      BUSINESS_LIMITS,
100	  brand_workspace: BUSINESS_LIMITS,
101	};
102	
103	const ACTIVE_STATUSES = new Set(["active", "trialing"]);
104	
105	export const useSubscription = (): SubscriptionState => {
106	  const [plan, setPlan] = useState<SubscriptionPlan>("free");
107	  const [status, setStatus] = useState("inactive");
108	  const [isLoading, setIsLoading] = useState(true);
109	  const [kiraActionsToday, setKiraActionsToday] = useState(0);
110	  const [kiraActionsLimit, setKiraActionsLimit] = useState(10);
111	  const [invoicesUsedThisMonth, setInvoicesUsedThisMonth] = useState(0);
112	  const [canvasesUsedThisMonth, setCanvasesUsedThisMonth] = useState(0);
113	
114	  const applyProfile = (profile: Record<string, unknown>) => {
115	    setPlan((profile.subscription_plan as SubscriptionPlan) || "free");
116	    setStatus((profile.subscription_status as string) || "inactive");
117	    setKiraActionsToday((profile.kira_actions_used as number) || 0);
118	    setKiraActionsLimit((profile.kira_actions_limit as number) || 10);
119	    setInvoicesUsedThisMonth((profile.invoices_used_this_month as number) || 0);
120	    setCanvasesUsedThisMonth((profile.canvases_used_this_month as number) || 0);
121	  };
122	
123	  useEffect(() => {
124	    let channel: ReturnType<typeof supabase.channel> | null = null;
125	
126	    const setup = async () => {
127	      const { data: { user } } = await supabase.auth.getUser();
128	      if (!user) {
129	        setIsLoading(false);
130	        return;
131	      }
132	
133	      const { data: profile } = await supabase
134	        .from("profiles")
135	        .select("subscription_plan, subscription_status, kira_actions_used, kira_actions_limit, invoices_used_this_month, canvases_used_this_month")
136	        .eq("id", user.id)
137	        .single();
138	
139	      if (profile) applyProfile(profile as Record<string, unknown>);
140	      setIsLoading(false);
141	
142	      channel = supabase
143	        .channel(`subscription:${user.id}`)
144	        .on(
145	          "postgres_changes",
146	          {
147	            event: "UPDATE",
148	            schema: "public",
149	            table: "profiles",
150	            filter: `id=eq.${user.id}`,
151	          },
152	          (payload) => {
153	            applyProfile(payload.new as Record<string, unknown>);
154	          }
155	        )
156	        .subscribe();
157	    };
158	
159	    setup();
160	
161	    return () => {
162	      if (channel) supabase.removeChannel(channel);
163	    };
164	  }, []);
165	
166	  const currentPlan = plan || "free";
167	  const limits = PLAN_LIMITS[currentPlan] ?? PLAN_LIMITS["free"];
168	  const isActiveStatus = ACTIVE_STATUSES.has(status);
169	
170	  return {
171	    plan: currentPlan,
172	    status,
173	    isLoading,
174	    isPro: (currentPlan === "pro" || currentPlan === "creative_pro") && isActiveStatus,
175	    isBusiness: (currentPlan === "business" || currentPlan === "brand_workspace") && isActiveStatus,
176	    isBrandWorkspace: (currentPlan === "brand_workspace" || currentPlan === "business") && isActiveStatus,
177	    isFree: (currentPlan === "free") || !isActiveStatus,
178	    limits,
179	    kiraActionsToday,
180	    kiraActionsLimit,
181	    invoicesUsedThisMonth,
182	    canvasesUsedThisMonth,
183	  };
184	};
185

1	-- ============================================================
2	-- Feature gating: 2 invoices + 2 contracts per month for free users
3	-- Pattern mirrors consume_kira_action (atomic FOR UPDATE + monthly reset)
4	-- ============================================================
5	
6	-- ── 1. Usage counters on profiles ────────────────────────────
7	ALTER TABLE public.profiles
8	  ADD COLUMN IF NOT EXISTS invoices_used_this_month  INTEGER NOT NULL DEFAULT 0,
9	  ADD COLUMN IF NOT EXISTS invoices_usage_month      TEXT,
10	  ADD COLUMN IF NOT EXISTS contracts_used_this_month INTEGER NOT NULL DEFAULT 0,
11	  ADD COLUMN IF NOT EXISTS contracts_usage_month     TEXT;
12	
13	-- ── 2. BEFORE INSERT trigger: invoices ───────────────────────
14	CREATE OR REPLACE FUNCTION public.enforce_invoice_limit()
15	RETURNS TRIGGER
16	LANGUAGE plpgsql
17	SECURITY DEFINER
18	SET search_path = public
19	AS $$
20	DECLARE
21	  v_plan  TEXT;
22	  v_used  INTEGER;
23	  v_month TEXT;
24	BEGIN
25	  SELECT subscription_plan, invoices_used_this_month, invoices_usage_month
26	    INTO v_plan, v_used, v_month
27	    FROM profiles
28	   WHERE id = NEW.user_id
29	     FOR UPDATE;
30	
31	  -- Unknown user → allow (RLS handles auth)
32	  IF NOT FOUND THEN RETURN NEW; END IF;
33	
34	  -- Paid plans: unlimited
35	  IF v_plan IN ('creative_pro', 'brand_workspace') THEN RETURN NEW; END IF;
36	
37	  -- Monthly reset
38	  IF v_month IS DISTINCT FROM TO_CHAR(CURRENT_DATE, 'YYYY-MM') THEN
39	    UPDATE profiles
40	       SET invoices_used_this_month = 0,
41	           invoices_usage_month     = TO_CHAR(CURRENT_DATE, 'YYYY-MM')
42	     WHERE id = NEW.user_id;
43	    v_used := 0;
44	  END IF;
45	
46	  IF v_used >= 2 THEN
47	    RAISE EXCEPTION 'invoice_limit_reached'
48	      USING HINT = 'Free plan allows 2 invoices per month. Upgrade to Pro for unlimited.';
49	  END IF;
50	
51	  UPDATE profiles
52	     SET invoices_used_this_month = invoices_used_this_month + 1
53	   WHERE id = NEW.user_id;
54	
55	  RETURN NEW;
56	END;
57	$$;
58	
59	DROP TRIGGER IF EXISTS trg_enforce_invoice_limit ON public.invoices;
60	CREATE TRIGGER trg_enforce_invoice_limit
61	  BEFORE INSERT ON public.invoices
62	  FOR EACH ROW EXECUTE FUNCTION public.enforce_invoice_limit();
63	
64	-- ── 3. BEFORE INSERT trigger: contracts ──────────────────────
65	CREATE OR REPLACE FUNCTION public.enforce_contract_limit()
66	RETURNS TRIGGER
67	LANGUAGE plpgsql
68	SECURITY DEFINER
69	SET search_path = public
70	AS $$
71	DECLARE
72	  v_plan  TEXT;
73	  v_used  INTEGER;
74	  v_month TEXT;
75	BEGIN
76	  SELECT subscription_plan, contracts_used_this_month, contracts_usage_month
77	    INTO v_plan, v_used, v_month
78	    FROM profiles
79	   WHERE id = NEW.user_id
80	     FOR UPDATE;
81	
82	  IF NOT FOUND THEN RETURN NEW; END IF;
83	
84	  IF v_plan IN ('creative_pro', 'brand_workspace') THEN RETURN NEW; END IF;
85	
86	  IF v_month IS DISTINCT FROM TO_CHAR(CURRENT_DATE, 'YYYY-MM') THEN
87	    UPDATE profiles
88	       SET contracts_used_this_month = 0,
89	           contracts_usage_month     = TO_CHAR(CURRENT_DATE, 'YYYY-MM')
90	     WHERE id = NEW.user_id;
91	    v_used := 0;
92	  END IF;
93	
94	  IF v_used >= 2 THEN
95	    RAISE EXCEPTION 'contract_limit_reached'
96	      USING HINT = 'Free plan allows 2 contracts per month. Upgrade to Pro for unlimited.';
97	  END IF;
98	
99	  UPDATE profiles
100	     SET contracts_used_this_month = contracts_used_this_month + 1
101	   WHERE id = NEW.user_id;
102	
103	  RETURN NEW;
104	END;
105	$$;
106	
107	DROP TRIGGER IF EXISTS trg_enforce_contract_limit ON public.contracts;
108	CREATE TRIGGER trg_enforce_contract_limit
109	  BEFORE INSERT ON public.contracts
110	  FOR EACH ROW EXECUTE FUNCTION public.enforce_contract_limit();
111	
112	-- ── 4. Read-only gate checks for the UI ──────────────────────
113	-- Returns { allowed, used, limit, remaining } so the UI can gate
114	-- the Create button before attempting an insert.
115	
116	CREATE OR REPLACE FUNCTION public.can_create_invoice()
117	RETURNS JSON
118	LANGUAGE plpgsql
119	SECURITY DEFINER
120	SET search_path = public
121	AS $$
122	DECLARE
123	  v_plan  TEXT;
124	  v_used  INTEGER;
125	  v_month TEXT;
126	  v_limit CONSTANT INTEGER := 2;
127	BEGIN
128	  SELECT subscription_plan, invoices_used_this_month, invoices_usage_month
129	    INTO v_plan, v_used, v_month
130	    FROM profiles
131	   WHERE id = auth.uid();
132	
133	  IF NOT FOUND THEN
134	    RETURN json_build_object('allowed', false, 'used', 0, 'limit', v_limit, 'remaining', 0);
135	  END IF;
136	
137	  IF v_plan IN ('creative_pro', 'brand_workspace') THEN
138	    RETURN json_build_object('allowed', true, 'used', v_used, 'limit', null, 'remaining', null);
139	  END IF;
140	
141	  IF v_month IS DISTINCT FROM TO_CHAR(CURRENT_DATE, 'YYYY-MM') THEN
142	    v_used := 0;
143	  END IF;
144	
145	  RETURN json_build_object(
146	    'allowed',    v_used < v_limit,
147	    'used',       v_used,
148	    'limit',      v_limit,
149	    'remaining',  GREATEST(0, v_limit - v_used)
150	  );
151	END;
152	$$;
153	
154	CREATE OR REPLACE FUNCTION public.can_create_contract()
155	RETURNS JSON
156	LANGUAGE plpgsql
157	SECURITY DEFINER
158	SET search_path = public
159	AS $$
160	DECLARE
161	  v_plan  TEXT;
162	  v_used  INTEGER;
163	  v_month TEXT;
164	  v_limit CONSTANT INTEGER := 2;
165	BEGIN
166	  SELECT subscription_plan, contracts_used_this_month, contracts_usage_month
167	    INTO v_plan, v_used, v_month
168	    FROM profiles
169	   WHERE id = auth.uid();
170	
171	  IF NOT FOUND THEN
172	    RETURN json_build_object('allowed', false, 'used', 0, 'limit', v_limit, 'remaining', 0);
173	  END IF;
174	
175	  IF v_plan IN ('creative_pro', 'brand_workspace') THEN
176	    RETURN json_build_object('allowed', true, 'used', v_used, 'limit', null, 'remaining', null);
177	  END IF;
178	
179	  IF v_month IS DISTINCT FROM TO_CHAR(CURRENT_DATE, 'YYYY-MM') THEN
180	    v_used := 0;
181	  END IF;
182	
183	  RETURN json_build_object(
184	    'allowed',    v_used < v_limit,
185	    'used',       v_used,
186	    'limit',      v_limit,
187	    'remaining',  GREATEST(0, v_limit - v_used)
188	  );
189	END;
190	$$;
191	
192	GRANT EXECUTE ON FUNCTION public.can_create_invoice()  TO authenticated;
193	GRANT EXECUTE ON FUNCTION public.can_create_contract() TO authenticated;
