1	import { useState, useEffect, useRef } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import {
4	  Dialog,
5	  DialogContent,
6	  DialogHeader,
7	  DialogTitle,
8	} from "@/components/ui/dialog";
9	import { Input } from "@/components/ui/input";
10	import { Button } from "@/components/ui/button";
11	import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
12	import { Badge } from "@/components/ui/badge";
13	import { toast } from "sonner";
14	import { Users, Search, UserPlus, X, Loader2, Crown, Link2, Copy, Check, ShieldCheck, ShieldOff } from "lucide-react";
15	
16	interface Member {
17	  user_id: string;
18	  role: string;
19	  profile: {
20	    display_name: string | null;
21	    email: string | null;
22	    avatar_url: string | null;
23	  };
24	}
25	
26	interface SearchResult {
27	  id: string;
28	  display_name: string | null;
29	  email: string | null;
30	  avatar_url: string | null;
31	}
32	
33	interface Props {
34	  open: boolean;
35	  onOpenChange: (open: boolean) => void;
36	  roomId: string;
37	  createdBy: string;
38	  currentUserId: string;
39	}
40	
41	const WorkspaceMembersDialog = ({ open, onOpenChange, roomId, createdBy, currentUserId }: Props) => {
42	  const [members, setMembers] = useState<Member[]>([]);
43	  const [loadingMembers, setLoadingMembers] = useState(true);
44	  const [search, setSearch] = useState("");
45	  const [searchResults, setSearchResults] = useState<SearchResult[]>([]);
46	  const [searching, setSearching] = useState(false);
47	  const [addingId, setAddingId] = useState<string | null>(null);
48	  const [removingId, setRemovingId] = useState<string | null>(null);
49	  const [promotingId, setPromotingId] = useState<string | null>(null);
50	  const [generatingLink, setGeneratingLink] = useState(false);
51	  const [copiedLink, setCopiedLink] = useState(false);
52	  const searchTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
53	  const isCreator = currentUserId === createdBy;
54	
55	  useEffect(() => {
56	    if (open) {
57	      fetchMembers();
58	      setSearch("");
59	      setSearchResults([]);
60	    }
61	  }, [open, roomId]);
62	
63	  const fetchMembers = async () => {
64	    setLoadingMembers(true);
65	    const { data } = await supabase
66	      .from("chat_room_members")
67	      .select("user_id, role")
68	      .eq("room_id", roomId);
69	
70	    if (!data) { setLoadingMembers(false); return; }
71	
72	    const profileIds = data.map((m) => m.user_id);
73	    const { data: profiles } = await supabase
74	      .from("profiles")
75	      .select("id, display_name, email, avatar_url")
76	      .in("id", profileIds);
77	
78	    const profileMap = Object.fromEntries((profiles || []).map((p) => [p.id, p]));
79	    setMembers(
80	      data.map((m) => ({
81	        user_id: m.user_id,
82	        role: m.role,
83	        profile: profileMap[m.user_id] || { display_name: null, email: null, avatar_url: null },
84	      }))
85	    );
86	    setLoadingMembers(false);
87	  };
88	
89	  const handleSearchChange = (value: string) => {
90	    setSearch(value);
91	    if (searchTimer.current) clearTimeout(searchTimer.current);
92	    if (!value.trim()) { setSearchResults([]); return; }
93	
94	    searchTimer.current = setTimeout(async () => {
95	      setSearching(true);
96	      const excludeIds = [currentUserId, ...members.map((m) => m.user_id)];
97	      let query = supabase
98	        .from("profiles")
99	        .select("id, display_name, email, avatar_url")
100	        .or(`email.ilike.%${value}%,display_name.ilike.%${value}%`)
101	        .limit(6);
102	
103	      if (excludeIds.length > 0) {
104	        query = query.not("id", "in", `(${excludeIds.join(",")})`);
105	      }
106	
107	      const { data } = await query;
108	      setSearchResults(data || []);
109	      setSearching(false);
110	    }, 300);
111	  };
112	
113	  const addMember = async (user: SearchResult) => {
114	    setAddingId(user.id);
115	    const { error } = await supabase
116	      .from("chat_room_members")
117	      .insert({ room_id: roomId, user_id: user.id, role: "member" });
118	
119	    if (error) {
120	      toast.error("Failed to add member");
121	    } else {
122	      toast.success(`${user.display_name || user.email} added to workspace`);
123	      setSearchResults((prev) => prev.filter((r) => r.id !== user.id));
124	      setSearch("");
125	      fetchMembers();
126	    }
127	    setAddingId(null);
128	  };
129	
130	  const removeMember = async (userId: string) => {
131	    setRemovingId(userId);
132	    const { error } = await supabase
133	      .from("chat_room_members")
134	      .delete()
135	      .eq("room_id", roomId)
136	      .eq("user_id", userId);
137	
138	    if (error) {
139	      toast.error("Failed to remove member");
140	    } else {
141	      setMembers((prev) => prev.filter((m) => m.user_id !== userId));
142	      toast.success("Member removed");
143	    }
144	    setRemovingId(null);
145	  };
146	
147	  const toggleRole = async (userId: string, currentRole: string) => {
148	    setPromotingId(userId);
149	    const newRole = currentRole === "admin" ? "member" : "admin";
150	    const { error } = await supabase
151	      .from("chat_room_members")
152	      .update({ role: newRole })
153	      .eq("room_id", roomId)
154	      .eq("user_id", userId);
155	    if (error) {
156	      toast.error("Failed to update role");
157	    } else {
158	      setMembers((prev) =>
159	        prev.map((m) => m.user_id === userId ? { ...m, role: newRole } : m)
160	      );
161	      toast.success(newRole === "admin" ? "Promoted to admin" : "Demoted to member");
162	    }
163	    setPromotingId(null);
164	  };
165	
166	  const generateInviteLink = async () => {
167	    setGeneratingLink(true);
168	    try {
169	      const { data, error } = await supabase
170	        .from("workspace_invites" as any)
171	        .insert({ room_id: roomId, invited_by: currentUserId })
172	        .select("token")
173	        .single();
174	      if (error) throw error;
175	      const link = `${window.location.origin}/invite/${(data as any).token}`;
176	      await navigator.clipboard.writeText(link);
177	      setCopiedLink(true);
178	      setTimeout(() => setCopiedLink(false), 2500);
179	      toast.success("Invite link copied to clipboard");
180	    } catch {
181	      toast.error("Failed to generate invite link");
182	    } finally {
183	      setGeneratingLink(false);
184	    }
185	  };
186	
187	  const getInitial = (profile: SearchResult | Member["profile"]) =>
188	    profile.display_name?.charAt(0) || profile.email?.charAt(0) || "?";
189	
190	  const getName = (profile: SearchResult | Member["profile"]) =>
191	    profile.display_name || profile.email || "Unknown";
192	
193	  return (
194	    <Dialog open={open} onOpenChange={onOpenChange}>
195	      <DialogContent className="sm:max-w-md">
196	        <DialogHeader>
197	          <DialogTitle className="flex items-center gap-2">
198	            <Users className="w-4 h-4 text-bronze" />
199	            Workspace Members
200	          </DialogTitle>
201	        </DialogHeader>
202	
203	        <div className="space-y-4">
204	          {/* Invite link — creator only */}
205	          {isCreator && (
206	            <button
207	              onClick={generateInviteLink}
208	              disabled={generatingLink}
209	              className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl border border-dashed border-bronze/30 bg-bronze/5 hover:bg-bronze/10 hover:border-bronze/50 transition-all text-left group"
210	            >
211	              <div className="w-7 h-7 rounded-lg bg-bronze/15 flex items-center justify-center flex-shrink-0">
212	                <Link2 className="w-3.5 h-3.5 text-bronze" />
213	              </div>
214	              <div className="flex-1 min-w-0">
215	                <p className="text-xs font-semibold text-foreground">Share Invite Link</p>
216	                <p className="text-[10px] text-muted-foreground">Anyone with the link can join</p>
217	              </div>
218	              {generatingLink
219	                ? <Loader2 className="w-3.5 h-3.5 animate-spin text-bronze flex-shrink-0" />
220	                : copiedLink
221	                ? <Check className="w-3.5 h-3.5 text-emerald-500 flex-shrink-0" />
222	                : <Copy className="w-3.5 h-3.5 text-bronze/60 group-hover:text-bronze flex-shrink-0 transition-colors" />
223	              }
224	            </button>
225	          )}
226	
227	          {/* Search to add */}
228	          {isCreator && (
229	            <div className="relative">
230	              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
231	              <Input
232	                value={search}
233	                onChange={(e) => handleSearchChange(e.target.value)}
234	                placeholder="Search by email or name to add..."
235	                className="pl-9 pr-4"
236	              />
237	              {searching && (
238	                <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 animate-spin text-muted-foreground" />
239	              )}
